// src/services/AuthService.ts
const BFF_BASE_URL = process.env.REACT_APP_BFF_URL || 'http://localhost:3001';

export interface LoginCredentials {
  email: string;
  password: string;
}

export interface AuthResponse {
  user: {
    userId: string;
    email: string;
    name: string;
    photoURL: string | null;
    role: string;
    createdAt: string;
  };
  token: string;
}

export interface ServiceResponse<T = any> {
  status: 'success' | 'error';
  data?: T;
  message?: string;
  retryable?: boolean;
}

class AuthService {
  async login(credentials: LoginCredentials): Promise<ServiceResponse<AuthResponse>> {
    try {
      if (!credentials.email || !credentials.password) {
        return {
          status: 'error',
          message: 'Invalid inputs',
          retryable: true,
        };
      }

      const response = await fetch(`${BFF_BASE_URL}/api/v1/auth/login`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      });

      if (response.status === 200) {
        const data = await response.json();
        return {
          status: 'success',
          data,
        };
      } else {
        const error = await response.json();
        return {
          status: 'error',
          message: error.error || 'Login failed',
          retryable: true,
        };
      }
    } catch (exception: any) {
      console.error('AuthService.login Failed', exception);
      return {
        status: 'error',
        message: 'Connection failed',
        retryable: true,
      };
    }
  }

  async signup(credentials: LoginCredentials & { name: string; role?: string }): Promise<ServiceResponse<AuthResponse>> {
    try {
      if (!credentials.email || !credentials.password || !credentials.name) {
        return {
          status: 'error',
          message: 'Invalid inputs',
          retryable: true,
        };
      }

      const response = await fetch(`${BFF_BASE_URL}/api/v1/auth/signup`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      });

      if (response.status === 201 || response.status === 200) {
        const data = await response.json();
        return {
          status: 'success',
          data,
        };
      } else {
        const error = await response.json();
        return {
          status: 'error',
          message: error.error || 'Signup failed',
          retryable: true,
        };
      }
    } catch (exception: any) {
      console.error('AuthService.signup Failed', exception);
      return {
        status: 'error',
        message: 'Connection failed',
        retryable: true,
      };
    }
  }
}

export const authService = new AuthService();
